<script lang="ts">
	import { runOp } from "$lib/api/client";
	import type { GovernanceItem } from "$lib/api/types";
	import BudgetLight from "$lib/components/BudgetLight.svelte";
	import Countdown from "$lib/components/Countdown.svelte";
	import Icon from "$lib/components/Icon.svelte";
	import type { CostBreakdown, CostSession } from "$lib/data/cost";
	import { snackbar } from "$lib/stores/snackbar.svelte";
	let { data } = $props();
	let range=$state("7d"), dimension=$state<"agent"|"model"|"project">("model"), filter=$state(""), chip=$state<string|null>(null), receipt=$state<CostSession|null>(null), now=$state(Date.now()), busy=$state<string|null>(null);
	let dialog=$state<HTMLDialogElement|null>(null);
	const canAct=$derived(data.lanes.includes("operator"));
	const pct=$derived(data.pool?Math.round(data.pool.pool_spent/Math.max(1,data.pool.pool_tokens)*100):null);
	const light=$derived(data.isMock?"green":null);
	const rows=$derived((data.breakdowns[dimension] as CostBreakdown[]).filter(r=>!filter||r.label.toLowerCase().includes(filter.toLowerCase())));
	const money=(n:number)=>"$"+n.toFixed(2), compact=(n:number)=>n>=1e6?(n/1e6).toFixed(2)+"M":Math.round(n/1e3)+"k", expires=(e?:number|null)=>e?new Date(e*1000).toISOString():null;
	function summaryReceipt(){receipt={id:"summary-7d",started:"7d",agent:"all residents",model:"mixed",tokens:"22.5M total",spend:41.2,source:"mixed",math:[{kind:"all priced usage",tokens:22_500_000,rate:0,dollars:41.2}]}}
	$effect(()=>{if(receipt&&dialog&&!dialog.open)dialog.showModal()}); $effect(()=>{const id=setInterval(()=>now=Date.now(),1000);return()=>clearInterval(id)});
	async function govern(g:GovernanceItem,action:"restore"|"throttle"|"downgrade"){busy=g.agent;try{await runOp("governance.action",{handle:g.agent,action,...(action==="throttle"?{delay_ms:60000}:{}),...(action==="downgrade"?{to:"sonnet"}:{})});snackbar.push({message:"governance.action "+action+" sent",op:"governance.action",tone:"good"})}catch(e){snackbar.push({message:(e as Error).message,op:"governance.action",tone:"danger"})}finally{busy=null}}
</script>
<svelte:window onkeydown={(e)=>{if(e.key==="Escape"){chip=null;dialog?.close()}}}/>
<header class="utility"><div class="sign"><h1>Cost</h1><span title="Every action has a value.">The Point System</span><small>{data.ledgerAvailable?"Ledger current. Synced 8s ago.":data.governanceAvailable?"Ledger unavailable. Governance is live.":"Can't verify. Ledger and governance unavailable."}</small></div><div class="seg">{#each ["Today","7d","30d","Billing"] as r}<button class:on={range===r} disabled={!data.ledgerAvailable||r!=="7d"} title={r==="Billing"?"Billing anchor is not contracted":r!=="7d"?"This fixture publishes the 7d window only":"7 day ledger"} onclick={()=>range=r}>{r}</button>{/each}</div><label><Icon name="search" size={14}/><input bind:value={filter} placeholder="Filter agent, model, project" aria-label="Filter cost ledger"/></label>{#if chip}<button class="chip" onclick={()=>chip=null}>{chip}<Icon name="x" size={11}/></button>{/if}</header>
<section class="strip"><div><small>Spend</small><b>{data.ledgerAvailable?"$41.20 this week":"—"}</b><span>{data.ledgerAvailable?"+18% vs last week":"query not contracted"}</span></div><div><small>Burn</small><b>{data.ledgerAvailable?"$1.36 today":"—"}</b><span>{data.ledgerAvailable?"38k tok/min now":"no ledger read"}</span></div><div><small>Pool</small><b><BudgetLight {light} label={light??"not served"}/>{pct===null?"—":pct+"%"}</b><span>{data.pool?compact(data.pool.pool_spent)+" of "+compact(data.pool.pool_tokens)+" tokens":"pool extension unavailable"}</span></div><div><small>Outlook</small><b>{data.ledgerAvailable?"Lasts to Thu Jul 16":"—"}</b><span>{data.ledgerAvailable?"exp smoothing · 92% interval":"forecast unavailable"}</span></div></section>
<div class="lens"><main><div class="top"><section class="panel chart"><h2>Spend by day</h2><p>This week against last · today is partial</p>{#if data.ledgerAvailable}<svg viewBox="0 0 540 96" role="img" aria-label="Daily spend this week"><line x1="8" y1="84" x2="532" y2="84"/><polyline points="16,45 100,16 184,36 268,40 352,31 436,56"/><text x="532" y="18" text-anchor="end">this week · $41.20</text></svg><div class="days">{#each data.daily as d}<button onclick={()=>chip="day = "+d.day}>{d.day}</button>{/each}</div>{@render Proof(summaryReceipt)}{:else}{@render Unavailable("Spend series")}{/if}</section><section class="panel stat"><h2>Total spend</h2><p>Mon to now, all residents</p>{#if data.ledgerAvailable}<strong>$41.20 <small>this week</small></strong><code>22.5M tokens · in 1.3M · out 0.7M · cache 20.5M</code><em><Icon name="coins" size={12}/>Cache saved $90.00 vs uncached</em>{@render Proof(summaryReceipt)}{:else}{@render Unavailable("Dollar and cache totals")}{/if}</section></div>
<section class="panel breakdown"><header><h2>Breakdown</h2><div class="seg">{#each ["agent","model","project"] as d}<button class:on={dimension===d} disabled={!data.ledgerAvailable} onclick={()=>dimension=d as typeof dimension}>By {d}</button>{/each}</div></header>{#if data.ledgerAvailable}{#each rows as row}<button onclick={()=>chip=dimension+" = "+row.label}><span>{row.label}</span><b>{row.spend===null?"—":money(row.spend)}</b><small>{row.share}%</small><i><em style:width={row.share+"%"}></em></i><code>{row.rate??""}</code></button>{/each}{@render Proof(summaryReceipt)}{:else}{@render Unavailable("Breakdown totals")}{/if}</section></main>
<aside><section class="panel price"><h2>Price book</h2><p>Per million tokens · USD · in / out / cache write / cache read</p>{#if data.ledgerAvailable}{#each data.prices as p}<button onclick={()=>chip="model = "+p.model}><code>{p.model}</code><span>{p.input.toFixed(2)} · {p.output.toFixed(2)} · {p.write?.toFixed(2)??"n/a"} · {p.read.toFixed(2)}</span></button>{/each}<footer>LiteLLM snapshot · 2026-07-02 · digest 9e1d<br/>Prices are config. Ask Janet to change them.</footer>{:else}{@render Unavailable("Model pricing")}{/if}</section><section class="panel grants"><h2>Points</h2>{#if data.pool}<div class="pool"><BudgetLight {light} label={light??"not served"}/><b>{compact(data.pool.pool_spent)} of {compact(data.pool.pool_tokens)}</b><span>· {pct}%</span></div>{:else}<p class="warn">Pool summary unavailable from the contracted envelope.</p>{/if}{#each data.governance as g}<div class="grant"><BudgetLight light={g.light} label={g.light}/><b>{g.agent}</b><code>{compact(g.tokens_spent)} of {g.granted_tokens==null?"—":compact(g.granted_tokens)}</code>{#if expires(g.grant_expires_epoch)}<Countdown expiresAt={expires(g.grant_expires_epoch)!} {now}/>{/if}<div>{#if canAct}{#if g.light==="red"}<button disabled={!data.controlPlaneLive||busy===g.agent} onclick={()=>govern(g,"restore")}>Restore</button>{/if}<button disabled={!data.controlPlaneLive||busy===g.agent} onclick={()=>govern(g,"throttle")}>Throttle</button><button disabled={!data.controlPlaneLive||busy===g.agent} onclick={()=>govern(g,"downgrade")}>Tier down</button>{/if}</div></div>{/each}<footer>Grants are leases. Unspent tokens return to the pool.</footer></section></aside></div>
{#if data.ledgerAvailable}<section class="cards">{#each data.agents as a}<button onclick={()=>chip="agent = "+a.handle}><header><span class="avatar">{a.handle[0]}</span><b>{a.handle}</b><strong>{money(a.spend)}</strong></header><code>{a.tokens}</code><div class="mix">{#each a.mix as m,i}<i class:m2={i===1} class:m3={i>1} style:width={m.share+"%"}></i>{/each}</div><footer><BudgetLight light={a.governance.light}/>{compact(a.governance.tokens_spent)} of {compact(a.governance.granted_tokens??0)}<span>{a.governance.tier}</span><Icon name="receipt-text" size={12}/></footer></button>{/each}</section><section class="panel ledger"><h2>Session ledger</h2>{#each data.sessions as s}<button onclick={()=>receipt=s}><time>{s.started}</time><b>{s.agent}</b><code>{s.model}</code><span>{s.taskId?"task "+s.taskId:"no lease"}</span><code>{s.tokens}</code><strong>{money(s.spend)}</strong><Icon name="receipt-text" size={12}/></button>{/each}</section>{/if}
<dialog bind:this={dialog} aria-labelledby="cost-receipt-title" onclose={()=>receipt=null}>{#if receipt}<button class="close" autofocus onclick={()=>dialog?.close()} aria-label="Close"><Icon name="x" size={16}/></button><h2 id="cost-receipt-title">Receipt · {receipt.agent} · {receipt.started}</h2><table><tbody>{#each receipt.math as l}<tr><td>{l.kind}</td><td>{l.tokens.toLocaleString()} × USD {l.rate.toFixed(2)} /M</td><td>{money(l.dollars)}</td></tr>{/each}<tr><td>Points posted.</td><td>sum</td><td>{money(receipt.spend)}</td></tr></tbody></table><h3>Cost source · {receipt.source}</h3><p>matched exact · LiteLLM snapshot 2026-07-02 · digest 9e1d</p><pre>SELECT model, sum(input_tokens) FROM usage_events WHERE session_id = :session_id GROUP BY model</pre>{/if}</dialog>
{#snippet Proof(onopen:()=>void)}<button class="proof" onclick={onopen}><Icon name="receipt-text" size={12}/>ledger · query receipt<b>Show the math.</b></button>{/snippet}{#snippet Unavailable(label:string)}<div class="unavailable"><Icon name="triangle-alert" size={14}/><b>{label} unavailable</b><span>The contract does not publish this ledger shape. Nothing rendered, nothing pretended.</span></div>{/snippet}
<style>
	.utility{min-height:40px;display:flex;align-items:center;gap:var(--s-3);flex-wrap:wrap}.sign{display:flex;align-items:baseline;gap:var(--s-3);flex:1}.sign h1,.sign span{font:400 1.25rem var(--sign)}.sign span{color:var(--jade-text)}.sign small,.panel p{font-size:.6875rem;color:var(--text-3)}.seg{display:flex;background:var(--s2);padding:2px;border-radius:var(--r-pill)}.seg button{border:0;background:none;color:var(--text-3);min-height:28px;border-radius:var(--r-pill)}.seg .on{background:var(--petal-soft);color:var(--petal-text)}.utility label{width:200px;background:var(--s2);display:flex;padding:var(--s-2);gap:var(--s-1)}input{border:0;background:none;width:100%}.chip{border:0;background:var(--jade-soft);color:var(--jade-text)}.strip{display:grid;grid-template-columns:auto auto auto 1fr;background:var(--s1);margin-top:var(--s-3)}.strip>div{display:flex;flex-direction:column;padding:var(--s-2) var(--s-3)}.strip>div+div{border-left:1px solid var(--rule)}.strip small{font:500 .6875rem var(--mono);text-transform:uppercase;color:var(--text-3)}.strip b{display:flex;gap:var(--s-2);font:500 .8125rem var(--mono)}.strip span{font-size:.6875rem;color:var(--text-3)}.lens{display:grid;grid-template-columns:minmax(0,1fr) 300px;gap:var(--s-3);margin-top:var(--s-3)}main,aside{display:flex;flex-direction:column;gap:var(--s-3)}.top{display:grid;grid-template-columns:7fr 5fr;gap:var(--s-3)}.panel,.cards>button{background:var(--s1);padding:var(--s-3);border-radius:var(--r-xs)}h2{font:500 .84375rem var(--sans)}.chart svg{width:100%;height:112px}.chart line{stroke:var(--rule)}.chart polyline{fill:none;stroke:var(--petal);stroke-width:2}.chart text{font:500 10px var(--mono);fill:var(--text-3)}.days{display:flex;justify-content:space-between}.days button,.proof{min-height:32px;border:0;background:none;color:var(--text-3);font:400 .6875rem var(--mono)}.proof{width:100%;display:flex;border-top:1px solid var(--rule);padding-top:var(--s-2)}.proof b{margin-left:auto;color:var(--petal-text)}.stat strong{font:500 1.75rem var(--mono)}.stat code{display:block;font-size:.6875rem}.stat em{display:flex;width:max-content;background:var(--good-soft);color:var(--good-text);font-style:normal;font-size:.75rem}.breakdown header{display:flex}.breakdown header .seg{margin-left:auto}.breakdown>button:not(.proof){width:100%;border:0;background:none;color:var(--text);display:grid;grid-template-columns:168px 64px 40px 1fr 120px;gap:var(--s-2);min-height:32px}.breakdown i{height:8px;background:var(--s3)}.breakdown em{display:block;height:100%;background:var(--petal)}.price>button{min-height:32px;display:grid;width:100%;border:0;border-bottom:1px solid var(--rule);background:none;color:var(--text);text-align:left}.price span,footer{font-size:.6875rem;color:var(--text-3)}.pool{display:flex;gap:var(--s-1)}.warn{color:var(--warn-text)!important}.grant{display:grid;grid-template-columns:28px 1fr auto auto;gap:var(--s-2);border-top:1px solid var(--rule);padding:var(--s-1) 0;font-size:.6875rem}.grant>div:last-child{grid-column:2/-1}.grant button{min-height:32px;border:0;background:var(--petal-soft);color:var(--petal-text)}.cards{display:grid;grid-template-columns:repeat(3,1fr);gap:var(--s-3);margin-top:var(--s-3)}.cards>button{border:0;color:var(--text);text-align:left}.cards header,.cards footer{display:flex;gap:var(--s-2)}.cards strong,.cards footer span{margin-left:auto}.avatar{width:24px;height:24px;border-radius:50%;background:var(--jade-soft)}.mix{display:flex;height:8px}.mix i{background:var(--petal)}.mix .m2{background:var(--info-dot)}.mix .m3{background:var(--rule-strong)}.ledger{margin-top:var(--s-3)}.ledger>button{width:100%;display:grid;grid-template-columns:90px 100px 150px 80px 1fr 64px 20px;border:0;border-top:1px solid var(--rule);background:none;color:var(--text);text-align:left}.unavailable{min-height:104px;display:flex;flex-direction:column;align-items:center;justify-content:center;text-align:center;color:var(--text-3);font-size:.6875rem}.unavailable b{color:var(--warn-text)}dialog{width:480px;max-width:calc(100% - 24px);border:0;background:var(--s2);color:var(--text);padding:var(--s-4)}.close{position:absolute;right:var(--s-3);border:0;background:none}dialog table{width:100%}pre{background:var(--s3);padding:var(--s-2)}button:disabled{opacity:.45}@media(max-width:1023px){.lens{grid-template-columns:1fr}.top{grid-template-columns:1fr}.cards{grid-template-columns:1fr}}@media(max-width:767px){.utility label{width:100%}.strip>div:nth-child(2),.chart,aside,.cards,.ledger{display:none}.breakdown>button:not(.proof){grid-template-columns:1fr 64px 40px}.breakdown i,.breakdown code{display:none}}
</style>
